AI_REFUSAL_PHRASES = (
    "i’m sorry",
    "i'm sorry",
    "i cannot help",
    "i can’t help",
    "i cannot assist",
    "i can’t assist",
    "i can not help",
    "sorry, but i can’t",
    "sorry, but i cannot",
    "Извини, я не могу",
    "я не могу",
    "Ошибка ИИ: Groq: Error code: 400",
)

AI_REFUSAL_REPLACEMENT = (
    "**ApiXS Guard Module**\n"
    "__Наш модуль зафиксировал цензуру. Если хочешь — переформулируй вопрос или уточни контекст. \nЕсли считаете что произошла ошибка свяжитесь: @xselid__"
)


def replace_ai_refusal(text: str) -> str:
    if not text:
        return text
    low = text.lower()
    for phrase in AI_REFUSAL_PHRASES:
        if phrase in low:
            return AI_REFUSAL_REPLACEMENT
    return text


def format_ai_reply(text: str) -> str:
    """Делает ответ ИИ читаемым в чате: убирает #, таблицы, лишние разделители."""
    if not text or not text.strip():
        return text
    lines = text.split("\n")
    out = []
    for line in lines:
        s = line.strip()
        if not s:
            out.append("")
            continue
        if s.startswith("---") or s.startswith("___") or set(s.strip("-_ ")) <= {"-", "_", " "}:
            out.append("")
            continue
        if s.startswith("##"):
            out.append("*" + s.lstrip("#").strip() + "*")
            continue
        if s.startswith("#"):
            out.append("*" + s.lstrip("#").strip() + "*")
            continue
        if "|" in s and s.count("|") >= 2:
            cells = [c.strip() for c in s.split("|") if c.strip()]
            if not cells or all(c.replace("-", "").replace(" ", "") == "" for c in cells):
                continue
            out.append("• " + " — ".join(cells))
        else:
            out.append(s)
    return re.sub(r"\n{3,}", "\n\n", "\n".join(out)).strip()


async def _get_text_from_event_or_tail(event, tail: str) -> str:
    """Текст из tail или из сообщения, на которое ответили."""
    text = (tail or "").strip()
    if not text and event.is_reply and event.reply_to_msg_id:
        try:
            reply_msg = await event.get_reply_message()
            if reply_msg:
                text = (getattr(reply_msg, "message", None) or "").strip()
        except Exception:
            pass
    return text or ""


async def handle(event, tail: str, user_id: int, respond, config=None, prefix: str = ".axs", **kwargs) -> bool:
    if config is None:
        from ..config import load_config
        config = load_config()
    return await cmd_ai(event, config, tail, user_id, respond, prefix=prefix)


async def cmd_ai(event, config: Config, tail: str, user_id: int, respond, *, prefix: str | None = None) -> bool:
    p = prefix or config.command_prefix
    parts = parse_args(tail)
    first = (parts[0] if parts else "").lower()
    rest_str = " ".join(parts[1:]).strip() if len(parts) > 1 else ""

    # summarize / improve — работают с текстом из tail или из reply
    if first == "summarize":
        text = await _get_text_from_event_or_tail(event, rest_str)
        if not text:
            await respond(blockquote_html("Укажите текст или ответьте на сообщение. Пример: <code>ai summarize</code> или <code>ai summarize &lt;текст&gt;</code>"), parse_mode="html")
            return True
        system = "Сделай краткое саммари (3–5 предложений). Только суть, без вступлений."
        if config.is_bot:
            target = await event.reply("✍️ Summarizing…")
        else:
            await event.edit("✍️ Summarizing…")
            target = event
        try:
            reply = await groq_complete(api_key=config.groq_api_key, model=config.groq_model, prompt=text, system=system)
            reply = format_ai_reply(reply or "")
            await edit_with_anim(target, reply[:MAX_MSG], user_id)
        except Exception as e:
            logger.exception("AI summarize error")
            await target.edit("Ошибка: {}".format(e)[:MAX_MSG])
        return True

    if first == "improve":
        text = await _get_text_from_event_or_tail(event, rest_str)
        if not text:
            await respond(blockquote_html("Укажите текст или ответьте на сообщение. Пример: <code>ai improve</code> или <code>ai improve &lt;текст&gt;</code>"), parse_mode="html")
            return True
        system = "Улучши текст: грамматика, стиль, читаемость. Сохрани смысл. Ответь только улучшенным текстом."
        if config.is_bot:
            target = await event.reply("✍️ Improving…")
        else:
            await event.edit("✍️ Improving…")
            target = event
        try:
            reply = await groq_complete(api_key=config.groq_api_key, model=config.groq_model, prompt=text, system=system)
            reply = format_ai_reply(reply or "")
            try:
                status_metric_add("ai_request")
            except Exception:
                pass
            await edit_with_anim(target, reply[:MAX_MSG], user_id)
        except Exception as e:
            logger.exception("AI improve error")
            await target.edit("Ошибка: {}".format(e)[:MAX_MSG])
        return True

    if first == "translate":
        # .axs ai translate <lang> [text]  (или reply)
        tr_parts = parse_args(rest_str)
        lang = (tr_parts[0] if tr_parts else "").strip()
        text_tail = " ".join(tr_parts[1:]).strip() if len(tr_parts) > 1 else ""
        text = await _get_text_from_event_or_tail(event, text_tail)
        if not lang or not text:
            await respond(blockquote_html(f"Формат: <code>{p} ai translate &lt;язык&gt; [текст]</code> или ответ на сообщение: <code>{p} ai translate &lt;язык&gt;</code>"), parse_mode="html")
            return True

        system = (
            "Переведи текст на указанный язык. "
            "Ответь только переводом, без пояснений. "
            + AI_FORMAT_RULES
        )
        prompt = "Язык: {}\n\nТекст:\n{}".format(lang, text)
        if config.is_bot:
            target = await event.reply("✍️ Translating…")
        else:
            await event.edit("✍️ Translating…")
            target = event
        try:
            reply = await groq_complete(api_key=config.groq_api_key, model=config.groq_model, prompt=prompt, system=system)
            reply = format_ai_reply(reply or "")
            try:
                status_metric_add("ai_request")
            except Exception:
                pass
            await edit_with_anim(target, reply[:MAX_MSG], user_id)
        except Exception as e:
            logger.exception("AI translate error")
            await target.edit("Ошибка: {}".format(e)[:MAX_MSG])
        return True

    if first == "mode":
        chat_id = event.chat_id
        allow_any = bool(rest_str and rest_str.split()[0].lower() == "list")
        if not allow_any and not event.is_private:
            await respond(blockquote_html("AI‑режим доступен только в личных чатах. Напишите команду в ЛС."), parse_mode="html")
            return True
        if not rest_str:
            cur = ai_mode_get(chat_id)
            if cur is None or not cur["on"]:
                await respond(blockquote_html(f"AI‑режим выключен. Включить: <code>{p} ai mode on</code> или <code>{p} ai mode on [детали]</code>"), parse_mode="html")
            else:
                det = cur["prompt_details"] or "(без доп. указаний)"
                await respond(blockquote_html("AI‑режим включён. Детали: " + str(det)[:200]), parse_mode="html")
            return True
        sub = rest_str.split(maxsplit=1)
        cmd = (sub[0] if sub else "").lower()
        details = (sub[1] if len(sub) > 1 else "").strip()
        if cmd == "list":
            rows = [(cid, det) for cid, on, det in ai_mode_list() if on]
            if not rows:
                await respond(blockquote_html("Нет чатов с включённым AI‑режимом."), parse_mode="html")
                return True
            lines = ["<b>AI включён:</b>"]
            for cid, det in rows:
                try:
                    ent = await event.client.get_entity(cid)
                    name = getattr(ent, "username", None) and "@" + ent.username or getattr(ent, "first_name", None) or str(cid)
                except Exception:
                    name = str(cid)
                detail = " — " + (det[:80] + "…" if len(det) > 80 else det) if det else ""
                lines.append("• {} ({}){}".format(name, cid, detail))
            await respond(blockquote_html("\n".join(lines)[:MAX_MSG - 50]), parse_mode="html")
            return True
        if cmd == "on":
            ai_mode_set(chat_id, True, details)
            msg = "AI‑режим запущен в этом чате."
            if details:
                msg += " Детали: " + details[:200]
            await respond(blockquote_html(msg), parse_mode="html")
            return True
        if cmd == "off":
            ai_mode_set(chat_id, False, "")
            ai_history_clear(chat_id)
            await respond(blockquote_html("AI‑режим выключен. История очищена."), parse_mode="html")
            return True
        await respond(blockquote_html(f"<code>{p} ai mode on [детали]</code> | <code>off</code> | <code>list</code>"), parse_mode="html")
        return True

    prompt = tail.strip()
    if not prompt:
        await respond(blockquote_html(
            f"<code>{p} ai &lt;вопрос&gt;</code> — разовый ответ.<br>"
            f"<code>{p} ai mode on [детали]</code> — включить AI‑режим в чате."
        ), parse_mode="html")
        return True
    if config.is_bot:
        target = await event.reply("Wait Data..")
    else:
        await event.edit("Wait Data..")
        target = event
    try:
        reply = await groq_complete(
            api_key=config.groq_api_key,
            model=config.groq_model,
            prompt=prompt,
            system=AI_FORMAT_RULES,
        )
        reply = replace_ai_refusal(reply or "")
        reply = format_ai_reply(reply)
        await edit_with_anim(target, reply, user_id)
    except Exception as e:
        import re
        err_msg = str(e)
        err_msg = re.sub(r"\b\d{8,10}:[A-Za-z0-9_-]{35}\b", "[TOKEN]", err_msg)
        err_msg = re.sub(r"\b(gsk_|sk-|AIza)[A-Za-z0-9_-]{20,}\b", "[API_KEY]", err_msg)
        logger.exception("AI error: %s", err_msg)
        err = "Ошибка ИИ: {}".format(err_msg)[:MAX_MSG]
        await target.edit(err)
    return True


def register_ai_mode_handler(client: TelegramClient, config: Config) -> None:
    """Регистрирует обработчик NewMessage для AI-режима в ЛС."""

    @client.on(events.NewMessage())
    async def on_ai_mode_msg(event):
        if config.is_bot:
            return
        if not event.is_private or event.out:
            return
        text = (getattr(event.message, "message", None) or "").strip()
        if not text or (config.command_prefix and text.startswith(config.command_prefix)):
            return
        chat_id = event.chat_id
        mode = ai_mode_get(chat_id)
        if not mode or not mode["on"]:
            return
        details = mode.get("prompt_details") or ""
        system = AI_MODE_BASE + "\n\n" + AI_FORMAT_RULES
        if details:
            system += "\nДополнительно: " + details
        history = ai_history_get(chat_id)

        async def _react(emoji: str) -> None:
            try:
                await client(
                    functions.messages.SendReactionRequest(
                        peer=event.chat_id,
                        msg_id=event.message.id,
                        reaction=[types.ReactionEmoji(emoticon=emoji)] if emoji else [],
                    )
                )
            except Exception as e:
                logger.debug("reaction %s: %s", emoji or "clear", e)

        await _react("👀")
        try:
            reply = await groq_complete(
                api_key=config.groq_api_key,
                model=config.groq_model,
                prompt=text,
                system=system,
                history=history,
            )
            reply = replace_ai_refusal(reply or "")
            reply = format_ai_reply(reply.strip())[:MAX_MSG]
            ai_history_add_turn(chat_id, text, reply)
            try:
                status_metric_add("ai_request")
            except Exception:
                pass
            await event.reply(reply)
        except Exception as e:
            import re
            err_msg = str(e)
            err_msg = re.sub(r"\b\d{8,10}:[A-Za-z0-9_-]{35}\b", "[TOKEN]", err_msg)
            err_msg = re.sub(r"\b(gsk_|sk-|AIza)[A-Za-z0-9_-]{20,}\b", "[API_KEY]", err_msg)
            logger.exception("AI mode reply error: %s", err_msg)
            await event.reply("Ошибка ИИ: {}".format(err_msg)[:MAX_MSG])
        finally:
            await _react("")
